  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Revisiones de Estimaciones de Coinbase — William Blair (2026-27)</text>
    <g font-family="sans-serif">
      <text x="20" y="58" fill="#a1a1aa" font-size="13">Nota de investigación del 15 de julio de 2026 — vs. estimaciones previas</text>
      <line x1="50" y1="330" x2="660" y2="330" stroke="#3f3f46" stroke-width="1.5"/>
      <rect x="90" y="245" width="90" height="85" rx="6" fill="#38bdf8"/>
      <text x="135" y="230" fill="#e4e4e7" font-size="16" font-weight="700" text-anchor="middle">-12%</text>
      <text x="135" y="355" fill="#71717a" font-size="12" text-anchor="middle">Ingresos 2026</text>
      <rect x="230" y="235" width="90" height="95" rx="6" fill="#38bdf8"/>
      <text x="275" y="220" fill="#e4e4e7" font-size="16" font-weight="700" text-anchor="middle">-13%</text>
      <text x="275" y="355" fill="#71717a" font-size="12" text-anchor="middle">Ingresos 2027</text>
      <rect x="370" y="105" width="90" height="225" rx="6" fill="#ef4444"/>
